"""Task 099 (444801d8): fill blue-outlined boxes with their seed colour + lid.

Rule (ARC-GEN): the 10x10 input holds 1-2 vertical blue(1)-outlined width-5
"boxes"; each carries one coloured "seed" pixel inside. The output paints every
interior background cell of a box AND a full-width "lid" row directly above the
box top with that box's seed colour; blue stays blue, everything else stays bg.

Tier S: the output colour at each cell is a LOCAL function of the input one-hot
window -- a painted cell's seed always lies within rows [-1..+3] and cols
[-2..+2] of it (measured on the generator), and the box shape is read from the
blue/background channels in the same window. So the whole map is a SINGLE Conv
input->output (memory 0). The scorer is per-channel (out>0), so each output
channel is a separating hyperplane over the local one-hot window; the 5x5 (10->10)
weights are fit by SGD on fresh generator samples (the public net used a 7x5
kernel = 3510 params; the asymmetric reach [-1..+3] rows only needs 5x5 = 2510).
Asymmetric vertical padding pads=[top=1,left=2,bottom=3,right=2] places the
window so a painted lid cell can see its seed 3 rows below it.
"""

import base64
import numpy as np
import onnx
from onnx import helper, numpy_helper, TensorProto

from ..harness import IR_VERSION

_W_B64 = ""
_B_B64 = "7YCTv8wcjb/S2Iy/yDCNvxWnjL/MAo6/xAWOvxICjb8TyYy/MI2Nvw=="
KH, KW = 5, 5
PADS = [1, 2, 3, 2]  # top, left, bottom, right (ONNX Conv pads order)


def build(task):
    W = np.frombuffer(base64.b64decode(_W_B64), dtype=np.float32).reshape(10, 10, KH, KW).copy()
    B = np.frombuffer(base64.b64decode(_B_B64), dtype=np.float32).reshape(10).copy()
    inits = [numpy_helper.from_array(W, "W"), numpy_helper.from_array(B, "B")]
    node = helper.make_node(
        "Conv", ["input", "W", "B"], ["output"],
        kernel_shape=[KH, KW], pads=PADS)
    x = helper.make_tensor_value_info("input", TensorProto.FLOAT, [1, 10, 30, 30])
    y = helper.make_tensor_value_info("output", TensorProto.FLOAT, [1, 10, 30, 30])
    graph = helper.make_graph([node], "graph", [x], [y], inits)
    return helper.make_model(
        graph, ir_version=IR_VERSION,
        opset_imports=[helper.make_opsetid("", 11)])
